<?php
declare(strict_types=1);require_once __DIR__.'/_layout.php';$pdo=obtenerConexion();$docenteId=docenteSupervisadoAtenea($pdo);$curso=docenteId($_GET['curso']??0);if($curso)exigirCursoDocente($pdo,$docenteId,$curso);docenteCabecera('Estudiantes','estudiantes','Estudiantes relacionados con cursos asignados.');docenteSelectorSupervision($pdo);$busqueda=trim((string)($_GET['q']??''));$pagina=max(1,(int)($_GET['pagina']??1));$lim=20;$where=" WHERE ed.docente_id=:d";$pa=['d'=>$docenteId];if($curso){$where.=' AND ed.asignatura_id=:a';$pa['a']=$curso;}if($busqueda!==''){$where.=' AND (u.nombre LIKE :q OR u.apellido LIKE :q OR u.correo LIKE :q OR u.nombre_usuario LIKE :q)';$pa['q']='%'.$busqueda.'%';}$from=' FROM estudiantes_docentes ed JOIN usuarios u ON u.id=ed.estudiante_id JOIN asignaturas a ON a.id=ed.asignatura_id';$q=$pdo->prepare('SELECT COUNT(*)'.$from.$where);$q->execute($pa);$total=(int)$q->fetchColumn();$q=$pdo->prepare('SELECT ed.id,ed.estado,u.id estudiante_id,u.nombre,u.apellido,u.nombre_usuario,u.correo,a.id asignatura_id,a.nombre asignatura'.$from.$where.' ORDER BY u.nombre,u.apellido LIMIT :lim OFFSET :off');foreach($pa as$k=>$v)$q->bindValue(':'.$k,$v);$q->bindValue(':lim',$lim,PDO::PARAM_INT);$q->bindValue(':off',($pagina-1)*$lim,PDO::PARAM_INT);$q->execute();$filas=$q->fetchAll();?>
<div class="card card-rounded"><div class="card-body"><form class="row g-2 mb-4"><input type="hidden" name="docente_id" value="<?=$docenteId?>"><div class="col-md-8"><input class="form-control" name="q" value="<?=atenea_e($busqueda)?>" placeholder="Nombre, usuario o correo"></div><?php if($curso):?><input type="hidden" name="curso" value="<?=$curso?>"><?php endif;?><div class="col-md-4"><button class="btn btn-outline-primary w-100">Buscar</button></div></form><div class="table-responsive"><table class="table table-hover"><thead><tr><th>Estudiante</th><th>Usuario</th><th>Curso</th><th>Estado de matrícula</th><th></th></tr></thead><tbody><?php foreach($filas as$e):?><tr><td><?=atenea_e(trim($e['nombre'].' '.$e['apellido']))?><small class="d-block"><?=atenea_e($e['correo'])?></small></td><td><?=atenea_e($e['nombre_usuario'])?></td><td><?=atenea_e($e['asignatura'])?></td><td><?=atenea_e($e['estado'])?></td><td><a class="btn btn-sm btn-outline-primary" href="<?=docenteUrl('entregas.php',['curso'=>$e['asignatura_id'],'estudiante'=>$e['estudiante_id']])?>">Actividad académica</a></td></tr><?php endforeach;?><?php if(!$filas):?><tr><td colspan="5" class="text-center py-5">No hay estudiantes relacionados con estos filtros.</td></tr><?php endif;?></tbody></table></div><?=cmsPaginacionSimple($pagina,(int)ceil($total/$lim),$_GET)?></div></div><?php docentePie();
